const campaigns = $('Busca campanhas').first().json.data
const insights = $('Busca insights').first().json.data

for(const campaign of campaigns) {
  const campaignInsights = insights.find(i => String(i.campaign_id) === String(campaign.id)) 
  campaignInsights.generated_leads = campaignInsights.actions.find(a => a.action_type == 'lead')?.value || 0

  campaign.insights = campaignInsights
}

return {
  campaigns
}

const period_type_translated = 'Diário'
return {
  date_preset: "yesterday",
  period_type: "daily",
  period_type_translated,
  text: (() => {
    const d = new Date();
    d.setDate(d.getDate() - 1);
    const fmt = x => `${String(x.getDate()).padStart(2,'0')}/${String(x.getMonth()+1).padStart(2,'0')}/${x.getFullYear()}`;
    return `${period_type_translated} - ${fmt(d)}`;
  })()
};

const period_type_translated = 'Semanal'
return {
  date_preset: "last_7d",
  period_type: "weekly",
  period_type_translated,
  text: (() => {
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 7);
    const fmt = d => `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
    return `${period_type_translated} - ${fmt(start)} até ${fmt(end)}`;
  })()
};

const campaigns = $input.first().json.campaigns;

const campaignWithCalculatedInsights = [];

const result = campaigns.reduce((acc, campaign) => {
  const insights = campaign.insights;

  // 1. Data Extraction
  const spendValue = parseFloat(insights.spend || 0);
  const generatedLeads = parseInt(insights.generated_leads || 0);
  const impressions = parseInt(insights.impressions || 0);
  const clicks = parseInt(insights.clicks || 0); // Total clicks (All clicks: likes, profiles, links, etc.)

  // Extract specifically "link_click" from the actions array
  let linkClicks = 0;
  if (Array.isArray(insights.actions)) {
    const linkClickObj = insights.actions.find(a => a.action_type === 'link_click');
    if (linkClickObj) {
      linkClicks = parseInt(linkClickObj.value);
    }
  }

  // 2. Individual Calculations

  // CPL (Cost Per Lead)
  const individualCPL = generatedLeads > 0 ? (spendValue / generatedLeads) : 0;

  // Click -> Lead Rate (Conversion Rate: Leads / Link Clicks)
  const clickToLeadRate = linkClicks > 0 ? (generatedLeads / linkClicks) : 0;

  // CPC Individual (Spend / All Clicks)
  const individualCPC = clicks > 0 ? (spendValue / clicks) : 0;

  campaignWithCalculatedInsights.push({
    ...campaign, 
    insights: {
      ...campaign.insights,
      cpl: `R$ ${individualCPL.toFixed(2)}`, 
      cpc: `R$ ${individualCPC.toFixed(2)}`, // Added individual CPC
      clickToLead: `${(clickToLeadRate * 100).toFixed(2)}%`
    }
  });

  // 4. Accumulators
  return {
    totalSpend: acc.totalSpend + spendValue,
    totalLeads: acc.totalLeads + generatedLeads,
    totalImpressions: acc.totalImpressions + impressions,
    totalClicks: acc.totalClicks + clicks,         // For CTR & CPC (All clicks)
    totalLinkClicks: acc.totalLinkClicks + linkClicks // For Click->Lead (Link clicks)
  };
}, { totalSpend: 0, totalLeads: 0, totalImpressions: 0, totalClicks: 0, totalLinkClicks: 0 });

// 5. Global Indicators

// GLOBAL CPL
const globalCPL = result.totalLeads > 0 
  ? result.totalSpend / result.totalLeads 
  : 0;

// GLOBAL CPM
const globalCPM = result.totalImpressions > 0 
  ? (result.totalSpend / result.totalImpressions) * 1000 
  : 0;

// GLOBAL CPC (Total Spend / Total Clicks)
const globalCPC = result.totalClicks > 0 
  ? result.totalSpend / result.totalClicks 
  : 0;

// GLOBAL CTR (All Clicks / Impressions)
const globalCTR = result.totalImpressions > 0 
  ? (result.totalClicks / result.totalImpressions) * 100 
    : 0;

// GLOBAL Click -> Lead (Total Leads / Total Link Clicks)
const globalClickToLead = result.totalLinkClicks > 0
  ? (result.totalLeads / result.totalLinkClicks) * 100
  : 0;

return {
  spend: `R$ ${result.totalSpend.toFixed(2)}`,
  totalLeads: result.totalLeads,
  cpl: `R$ ${globalCPL.toFixed(2)}`, 
  cpm: `R$ ${globalCPM.toFixed(2)}`,
  cpc: `R$ ${globalCPC.toFixed(2)}`, // Global CPC Added
  ctr: `${globalCTR.toFixed(2)}%`,
  clickToLead: `${globalClickToLead.toFixed(2)}%`,
  campaignWithCalculatedInsights: campaignWithCalculatedInsights ?? undefined
}
